@@ adds Static Files section

diff --git a/middleware/static.go b/middleware/static.go
index 4526033..09a3078 100644
--- a/middleware/static.go
+++ b/middleware/static.go
@@ -60,6 +60,16 @@ type StaticConfig struct {
 	// DirectoryListTemplate is template to list directory contents
 	// Optional. Default to `directoryListHTMLTemplate` constant below.
 	DirectoryListTemplate string
+
+	// CacheControl sets the Cache-Control header value for served static files.
+	// If empty and MaxAge > 0, "public, max-age=<MaxAge>" is used automatically.
+	// Optional.
+	CacheControl string
+
+	// MaxAge sets the max-age value (in seconds) for the Cache-Control header.
+	// Used only when CacheControl is empty. If both are zero/empty, no Cache-Control header is set.
+	// Optional.
+	MaxAge int
 }
@@ -294,19 +294,24 @@
-				return serveFile(c, index, info)
+				return serveFile(c, index, info, config.CacheControl, config.MaxAge)
 			}
-			return serveFile(c, file, info)
+			return serveFile(c, file, info, config.CacheControl, config.MaxAge)
 		}
 	}, nil
 }
-func serveFile(c *echo.Context, file fs.File, info os.FileInfo) error {
+func serveFile(c *echo.Context, file fs.File, info os.FileInfo, cacheControl string, maxAge int) error {
 	ff, ok := file.(io.ReadSeeker)
 	if !ok {
 		return errors.New("file does not implement io.ReadSeeker")
 	}
+	if cacheControl != "" {
+		c.Response().Header().Set(echo.HeaderCacheControl, cacheControl)
+	} else if maxAge > 0 {
+		c.Response().Header().Set(echo.HeaderCacheControl, "public, max-age="+strconv.Itoa(maxAge))
+	}
 	http.ServeContent(c.Response(), c.Request(), info.Name(), info.ModTime(), ff)
 	return nil
 }
